--

CREATE TABLE public.prestations (
    id integer NOT NULL,
    atelier_id integer,
    code character varying(50) NOT NULL,
    nom character varying(200) NOT NULL,
    description text,
    categorie character varying(100) DEFAULT 'entretien'::character varying NOT NULL,
    sous_categorie character varying(100) DEFAULT NULL::character varying,
    prix_base_ht numeric(10,2) DEFAULT 0.00 NOT NULL,
    prix_base_ttc numeric(10,2) DEFAULT 0.00 NOT NULL,
    temps_estime_minutes integer DEFAULT 30 NOT NULL,
    delai_intervention_jours integer DEFAULT 1 NOT NULL,
    type_tarif character varying(50) DEFAULT 'forfait'::character varying NOT NULL,
    taux_horaire_applique character varying(50) DEFAULT 'standard'::character varying NOT NULL,
    type_vehicule character varying(50) DEFAULT 'tous'::character varying NOT NULL,
    cylindree_min integer,
    cylindree_max integer,
    is_active integer DEFAULT 1 NOT NULL,
    is_forfait integer DEFAULT 0 NOT NULL,
    is_promo integer DEFAULT 0 NOT NULL,
    prix_promo_ttc numeric(10,2) DEFAULT NULL::numeric,
    inclut_pieces integer DEFAULT 0 NOT NULL,
    description_pieces_incluses text,
    cout_pieces_incluses_ht numeric(10,2) DEFAULT 0.00 NOT NULL,
    marge_pieces_pourcent double precision DEFAULT 30 NOT NULL,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    garantie_jours integer,
    necessite_essai boolean DEFAULT true NOT NULL
);


ALTER TABLE public.prestations OWNER TO atelier;

