-- Name: prestations_id_seq; Type: SEQUENCE; Schema: public; Owner: atelier
--

ALTER TABLE public.prestations ALTER COLUMN id ADD GENERATED BY DEFAULT AS IDENTITY (
    SEQUENCE NAME public.prestations_id_seq
