--
-- Name: vo_remises_en_etat; Type: TABLE; Schema: public; Owner: atelier
--

CREATE TABLE public.vo_remises_en_etat (
    id integer NOT NULL,
    atelier_id integer,
    vo_purchase_id integer,
    vo_depot_vente_id integer,
    campaign_index integer DEFAULT 1 NOT NULL,
    titre character varying(180) NOT NULL,
    status character varying(40) DEFAULT 'a_chiffrer'::character varying NOT NULL,
    priority character varying(20) DEFAULT 'normale'::character varying NOT NULL,
    diagnostic_notes text,
    workshop_notes text,
    business_notes text,
    requested_by integer,
    validated_by integer,
    requested_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    validated_at timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    planned_for timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    started_at timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    completed_at timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    closed_at timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    created_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    updated_at timestamp(0) without time zone DEFAULT CURRENT_TIMESTAMP NOT NULL,
    signature_data text,
    signed_snapshot json,
    signed_hash character varying(64) DEFAULT NULL::character varying,
    signed_by integer,
    signed_at timestamp(0) without time zone DEFAULT NULL::timestamp without time zone,
    signed_ip character varying(64) DEFAULT NULL::character varying,
    signed_user_agent character varying(500) DEFAULT NULL::character varying,
    CONSTRAINT chk_vo_re_source CHECK (((
CASE
    WHEN (vo_purchase_id IS NOT NULL) THEN 1
    ELSE 0
END +
CASE
    WHEN (vo_depot_vente_id IS NOT NULL) THEN 1
    ELSE 0
END) = 1))
);


